param([Parameter(Mandatory=$true)][string]$LeagueCode,[Parameter(Mandatory=$true)][string]$Season,[Parameter(Mandatory=$true)][string]$MatchDate,[Parameter(Mandatory=$true)][string]$HomeTeam,[Parameter(Mandatory=$true)][string]$AwayTeam,[string]$Country='',[string]$League='',[string]$MatchTime='',[string]$Stage='',[string]$SourceReference='manual-registration',[string]$ProjectRoot='',[switch]$ValidateOnly)
$ErrorActionPreference='Stop';if([string]::IsNullOrWhiteSpace($ProjectRoot)){$ProjectRoot=Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)};$LeagueCode=$LeagueCode.Trim().ToUpperInvariant();$HomeTeam=$HomeTeam.Trim();$AwayTeam=$AwayTeam.Trim();if($HomeTeam-eq$AwayTeam-or$HomeTeam-eq''-or$AwayTeam-eq''){throw 'Invalid teams'};$d=[datetime]::MinValue;if(-not[datetime]::TryParseExact($MatchDate,'yyyy-MM-dd',[Globalization.CultureInfo]::InvariantCulture,[Globalization.DateTimeStyles]::None,[ref]$d)){throw 'MatchDate must be yyyy-MM-dd'}
$identity=@($LeagueCode,$Season,$MatchDate,$Stage,$HomeTeam,$AwayTeam)-join'|';$sha=[Security.Cryptography.SHA256]::Create();try{$bytes=[Text.Encoding]::UTF8.GetBytes($identity.ToUpperInvariant());$hex=[BitConverter]::ToString($sha.ComputeHash($bytes)).Replace('-','').ToLowerInvariant();$id='FAI-'+$hex.Substring(0,24)}finally{$sha.Dispose()};$row=[pscustomobject]@{MatchID=$id;Country=$Country;LeagueCode=$LeagueCode;League=$League;Season=$Season;MatchDate=$MatchDate;MatchTime=$MatchTime;Stage=$Stage;HomeTeam=$HomeTeam;AwayTeam=$AwayTeam;Status='SCHEDULED';SourceReference=$SourceReference;RegisteredAt=(Get-Date).ToUniversalTime().ToString('o')}
$matches=Join-Path $ProjectRoot 'data\standardized\matches_all.csv';if(Test-Path $matches){if(Import-Csv $matches -Encoding UTF8|Where-Object{$_.MatchID-eq$id}|Select-Object -First 1){throw "MatchID already exists in history: $id"}};$fixtures=Join-Path $ProjectRoot 'data\standardized\fixtures.csv';if(Test-Path $fixtures){if(Import-Csv $fixtures -Encoding UTF8|Where-Object{$_.MatchID-eq$id}|Select-Object -First 1){throw "MatchID already exists in fixtures: $id"}}
if(-not$ValidateOnly){$existing=@(Import-Csv $fixtures -Encoding UTF8);@($existing)+@($row)|Export-Csv $fixtures -NoTypeInformation -Encoding UTF8};$row|ConvertTo-Json
